import { useNavigate } from "react-router-dom";
import logo from "../assets/logo.png";

export default function Navbar() {
  const nav = useNavigate();

  return (
    <div style={{ background: "#f3f4f6", borderBottom: "1px solid #ccc" }}>

      {/* TOP BAR */}
      <div style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "10px 30px"
      }}>

        {/* LEFT (LOGO) */}
        <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
          <img
            src={logo}
            alt="logo"
            style={{ height: "70px", width: "100px", objectFit: "contain" }}
          />
        </div>

        {/* CENTER (TITLE) */}
        <h1 style={{
          position: "absolute",
          left: "50%",
          transform: "translateX(-50%)",
          fontSize: "32px",
          fontWeight: "bold"
        }}>
          AARV: Train Booking System
        </h1>

        {/* RIGHT (BUTTONS) */}
        <div>
          <button onClick={() => nav("/")} style={btnBlue}>Login</button>
          <button onClick={() => nav("/signup")} style={btnGreen}>Signup</button>
        </div>
      </div>

      {/* NAV MENU */}
      <div style={{
        display: "flex",
        justifyContent: "center",
        gap: "40px",
        padding: "10px"
      }}>
        <button onClick={() => nav("/home")} style={navBtn}>Home</button>
        <button onClick={() => nav("/my")} style={navBtn}>Bookings</button>
        <button style={navBtn}>Account</button>
      </div>

    </div>
  );
}

/* STYLES */
const btnBlue = {
  background: "#2563eb",
  color: "white",
  padding: "6px 14px",
  marginRight: "8px",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer"
};

const btnGreen = {
  background: "#22c55e",
  color: "white",
  padding: "6px 14px",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer"
};

const navBtn = {
  background: "#d1d5db",
  padding: "6px 20px",
  border: "none",
  borderRadius: "5px",
  cursor: "pointer"
};
